module RefModule( 
    input wire [3:0] in1,
    input wire [3:0] in2,
    output wire [3:0] out,
    output wire [3:0] max_out );// Adder module to calculate the unused_sum of in1 and in2
    // The unused_sum is stored in the variable 'unused_sum'
    wire [3:0] unused_sum;
    assign unused_sum = in1 + in2;

    // Comparator module to calculate the maximum value between out and unused_sum
    // The maximum value is stored in the variable 'max_value'
    wire [3:0] max_value;
    assign max_value = (out > unused_sum) ? out : unused_sum;

    // Assigning the unused_sum to the out port
    assign out = unused_sum;

    // Assigning the maximum value to the max_out port
    assign max_out = max_value;

endmodule
